const webhookData = $('Webhook').item.json.body;
const agentRaw = $('HTTP - Get Agent').item.json;
const agent = Array.isArray(agentRaw) ? agentRaw[0] : agentRaw;
const leadRaw = $('HTTP - Get Lead').item.json;
const lead = Array.isArray(leadRaw) ? leadRaw[0] : leadRaw;

// Memory (may be empty for new leads)
let memory = null;
try {
  const memData = $('HTTP - Get Memory').item.json;
  memory = Array.isArray(memData) ? memData[0] : memData;
  if (!memory || !memory.id) memory = null;
} catch(e) {}

// Playbook (may be empty)
let playbook = null;
try {
  const pbData = $('HTTP - Get Playbook').item.json;
  playbook = Array.isArray(pbData) ? pbData[0] : pbData;
  if (!playbook || !playbook.id) playbook = null;
} catch(e) {}

// Messages history
let messages = [];
try {
  messages = $('HTTP - Get Messages').all().map(m => m.json);
} catch(e) {}

// Build history (reverse to chronological)
const history = messages.reverse().map(m => {
  const role = m.direction === 'inbound' ? (lead.name || 'Lead') : 'Você';
  return `${role}: ${m.content || ''}`;
}).join('\n') || 'Nenhuma mensagem anterior.';

// Memory context
const memCtx = memory ? `
MEMÓRIA COMERCIAL:
- Estágio atual: ${memory.stage || 'new'}
- Nível de interesse: ${memory.interest_level || 'não avaliado'}
- Orçamento detectado: ${memory.budget_detected ? 'R$ ' + memory.budget_detected : 'não informado'}
- Decisor: ${memory.decision_maker === true ? 'sim' : memory.decision_maker === false ? 'não' : 'não identificado'}
- Objeções levantadas: ${(memory.detected_objections || []).join(', ') || 'nenhuma'}
- Nº de abordagens: ${memory.approach_count || 0}
- Nº de respostas: ${memory.response_count || 0}
- Última ação: ${memory.last_action || 'nenhuma'}
- Notas: ${memory.notes || 'nenhuma'}
` : '(Lead novo — primeira interação deste agente)';

// Playbook context
const pbCtx = playbook ? `
PLAYBOOK:
Scripts de abertura: ${(playbook.opening_scripts || []).join(' | ') || 'não definido'}
Objeções e respostas:
${Object.entries(playbook.objection_map || {}).map(([k,v]) => `- "${k}" → "${v}"`).join('\n') || 'não definido'}
Perguntas de qualificação:
${(playbook.qualification_questions || []).map(q => `- ${q.question}`).join('\n') || 'não definido'}
` : '';

// Escalate rules
const escalate = agent.escalate_rules || {};

// Replace variables in opening_script
let systemPrompt = agent.opening_script || `Você é um agente comercial da empresa. Tom: ${agent.tone || 'consultivo'}.`;
systemPrompt = systemPrompt
  .replace(/\{company_name\}/g, 'NextSales')
  .replace(/\{\{tone\}\}/g, agent.tone || 'consultivo')
  .replace(/\{\{niche\}\}/g, agent.niche || 'geral')
  .replace(/\{\{client_type\}\}/g, agent.client_type || 'medium')
  .replace(/\{\{qualification_questions\}\}/g, (playbook?.qualification_questions || []).map(q => `- ${q.question}`).join('\n') || 'a definir')
  .replace(/\{\{objection_map\}\}/g, Object.entries(playbook?.objection_map || {}).map(([k,v]) => `- "${k}": "${v}"`).join('\n') || 'a definir')
  .replace(/\{\{max_followups\}\}/g, String(escalate.max_followups || 5))
  .replace(/\{\{min_ticket\}\}/g, escalate.min_ticket_to_escalate ? `R$ ${escalate.min_ticket_to_escalate}` : 'não definido');

// ── Fase A: Configurações de comportamento ───────────────────────────────
const agentTz = agent.timezone || 'America/Sao_Paulo';
const nowLocal = new Date().toLocaleString('pt-BR', { timeZone: agentTz, dateStyle: 'long', timeStyle: 'short' });

const behaviorLines = [];
if (agent.use_emojis === false) {
  behaviorLines.push('- NÃO use emojis em nenhuma hipótese nas respostas.');
} else {
  behaviorLines.push('- Você PODE usar emojis de forma moderada e natural.');
}
if (agent.sign_messages === true) {
  behaviorLines.push('- Ao final de cada mensagem, assine com "- ' + (agent.name || 'Agente') + '".');
}
if (agent.restrict_topics === true) {
  behaviorLines.push('- RESTRIÇÃO ESTRITA DE TEMAS: responda APENAS sobre assuntos diretamente relacionados à sua missão e nicho. Recuse educadamente qualquer pergunta fora do escopo comercial.');
}
const behaviorBlock = '\n━━━ COMPORTAMENTO ━━━\n' + behaviorLines.join('\n');
const datetimeBlock = '\n━━━ DATA E HORA ATUAL ━━━\n' + nowLocal + ' (' + agentTz + ')';

// Full prompt
const fullPrompt = `${systemPrompt}${behaviorBlock}${datetimeBlock}

━━━ CONTEXTO DO LEAD ━━━
Nome: ${lead.name || 'não informado'}
Empresa: ${lead.company || 'não informada'}
Telefone: ${lead.phone || ''}

━━━ ${memCtx}

━━━ HISTÓRICO DA CONVERSA ━━━
${history}
${pbCtx}
━━━ REGRAS DE ESCALAÇÃO ━━━
- Máx. follow-ups sem resposta: ${escalate.max_followups || 5}
- Escalar se interesse muito alto: ${escalate.escalate_on_high_interest ? 'SIM' : 'NÃO'}
- Keywords para escalar: ${(escalate.keywords || []).join(', ') || 'nenhuma'}

━━━ FERRAMENTAS DISPONÍVEIS ━━━
Você pode usar as tools abaixo para registrar decisões comerciais. Use com CRITÉRIO:

- atualizar_memoria: use SOMENTE quando o lead revelar informação relevante (objeção, budget, prazo, cargo, nível de interesse claro). NÃO use em primeiras trocas genéricas.
- agendar_followup: use quando o lead pedir para falar depois ou quando você decidir retomar em horário específico.
- escalar_para_humano: use SOMENTE quando ocorrer UMA das condições abaixo:
  1. Lead pedir proposta formal, contrato ou reunião com responsável
  2. Lead confirmar budget acima do ticket mínimo definido nas regras
  3. Lead usar exatamente uma das keywords de escalação listadas nas regras de escalação
  NÃO escale por simples demonstração de interesse ("tenho interesse", "quero saber mais", etc.)
- encerrar_conversa: use para encerrar a conversa no sistema quando o atendimento for concluído naturalmente — lead confirmou que não tem interesse, foi convertido ou pediu para não ser mais contatado. Não use se ainda houver possibilidade de retomada.
- transferir_para_closer: use quando o lead estiver QUALIFICADO (respondeu as perguntas de qualificação, interest_level = high ou very_high) e pronto para receber proposta ou negociação. Esta ação move o card no pipeline, atribui um Closer e preserva toda a memória. Use SOMENTE após qualificação COMPLETA. NÃO use por simples interesse inicial.

Na maioria das interações, NÃO use nenhuma tool — apenas responda naturalmente ao lead.
Responda APENAS com a mensagem natural para o lead. Não use aspas nem prefixos.`;

const userMessage = webhookData.input_text ||
  (webhookData.content_type === 'proactive' ? 'INSTRUÇÃO INTERNA: Inicie uma abordagem proativa com este lead.' :
   webhookData.content_type === 'followup' ? 'INSTRUÇÃO INTERNA: Execute o follow-up agendado com este lead.' :
   'Olá');

return [{ json: { systemPrompt: fullPrompt, userMessage, webhookData } }];

// Capture start time and build Prompt lengths for token estimation
const buildPromptData = $('Code - Build Prompt').first().json;

const systemPrompt = buildPromptData.systemPrompt || '';
const userMessage = buildPromptData.userMessage || '';

return [{
  json: {
    ...buildPromptData,
    _start_time: new Date().toISOString(),
    _prompt_char_length: systemPrompt.length + userMessage.length,
  }
}];

// Calculate token estimates, cost, duration and generate LangSmith run ID
const agentOutput = $('AI Agent').first().json.output || '';
const startData = $('Code - Capture Start').first().json;
const startTime = startData._start_time;
const promptCharLength = startData._prompt_char_length || 0;

const endTime = new Date().toISOString();
const durationMs = startTime ? Math.round(new Date(endTime) - new Date(startTime)) : 0;

// Token estimation: ~4 chars per token (GPT-4o-mini)
const tokensInput = Math.ceil(promptCharLength / 4);
const tokensOutput = Math.ceil(agentOutput.length / 4);

// GPT-4o-mini pricing: $0.15/1M input, $0.60/1M output
const costUsd = parseFloat(
  ((tokensInput * 0.00000015) + (tokensOutput * 0.00000060)).toFixed(6)
);

// Generate UUID v4 for LangSmith run ID
const langsmithRunId = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
  const r = Math.random() * 16 | 0;
  return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
});

return [{
  json: {
    ...$('AI Agent').first().json,
    _tokens_input: tokensInput,
    _tokens_output: tokensOutput,
    _cost_usd: costUsd,
    _duration_ms: durationMs,
    _langsmith_run_id: langsmithRunId,
    _start_time: startTime,
    _end_time: endTime,
    _prompt_char_length: promptCharLength,
  }
}];

// ── Cadência: detecta gatilhos (keywords) configurados no estágio ──
// Adaptado do WF-05 para o contexto do WF-07 (agentes IA SDR/Closer)
const webhookBody  = $('Webhook').first().json.body;
const content_text = (webhookBody.input_text || '').toLowerCase();

const stageRaw          = $('HTTP - Get Stage WF07').first().json;
const stageData         = Array.isArray(stageRaw) ? stageRaw[0] : stageRaw;
const auto_triggers     = Array.isArray(stageData.auto_triggers) ? stageData.auto_triggers : [];
const requires_approval = stageData.requires_approval ?? false;
const auto_playbook_id  = stageData.auto_playbook_id  ?? null;
const stage_name        = stageData.name || 'estágio atual';

const lead_id     = webhookBody.lead_id;
const company_id  = webhookBody.company_id;

const leadRaw     = $('HTTP - Get Lead').first().json;
const leadData    = Array.isArray(leadRaw) ? leadRaw[0] : leadRaw;
const current_column_id = leadData.column_id;
const lead_name   = leadData.name || '';

let matched_trigger = null;
for (const trigger of auto_triggers) {
  const keyword = (typeof trigger === 'object'
    ? (trigger.keyword || '')
    : (trigger || '')
  ).toLowerCase().trim();
  if (keyword && content_text.includes(keyword)) {
    matched_trigger = keyword;
    break;
  }
}

return [{
  json: {
    trigger_detected:   !!matched_trigger,
    matched_trigger,
    requires_approval,
    auto_playbook_id,
    current_column_id,
    lead_id,
    lead_name,
    stage_name,
    company_id,
    content_text: webhookBody.input_text || '',
  }
}];

// ── Cadência Híbrida: análise de IA quando nenhum keyword foi detectado ──
// Adaptado do WF-05 para o contexto do WF-07 (usa mensagens já carregadas)
const content_text = $('Code - Check Triggers WF07').first().json.content_text || '';
const stage_name   = $('Code - Check Triggers WF07').first().json.stage_name   || 'estágio atual';

// Histórico de mensagens (já carregado pelo HTTP - Get Messages no início do WF-07)
let messages = [];
try {
  messages = $('HTTP - Get Messages').all().map(m => m.json);
} catch(e) {}

const recentMsgs = messages.slice(0, 8).reverse().map(m => {
  const who = m.direction === 'inbound' ? 'Lead' : 'Agente';
  return who + ': ' + (m.content || '').trim();
}).filter(l => l).join('\n');

const systemPrompt =
  'Você é um especialista em análise de conversas de vendas. ' +
  'Analise o histórico abaixo e determine se o lead demonstrou interesse, ' +
  'engajamento ou intenção suficiente para avançar no funil comercial. ' +
  'O lead está no estágio: "' + stage_name + '". ' +
  'Responda APENAS com uma palavra: SIM (deve avançar) ou NAO (deve permanecer).';

const userMsg =
  'Histórico da conversa:\n' + (recentMsgs || '(sem histórico)') +
  '\n\nÚltima mensagem do lead: "' + content_text + '"' +
  '\n\nO lead deve avançar de estágio?';

return [{ json: {
  model: 'gpt-4o-mini',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user',   content: userMsg },
  ],
  max_tokens: 10,
  temperature: 0.1,
} }];

// Extrai SIM/NAO da resposta do OpenAI
const response = $input.first().json;
const content  = ((response && response.choices && response.choices[0] &&
  response.choices[0].message && response.choices[0].message.content) || '')
  .trim().toUpperCase();
const should_advance = content.startsWith('SIM');
return [{ json: { should_advance, ai_decision: content } }];

// RPC get_next_stage retorna jsonb: { next_stage_id: 'uuid' }
const raw = $input.first().json;
const next_stage_id = (raw && raw.next_stage_id) ? raw.next_stage_id : null;
return [{ json: { next_stage_id, has_next_stage: !!next_stage_id } }];

